// Cooldown Timer Class
class CooldownTimer {
  /**
   * Constructor
   * @param {number} duration - The duration of the cooldown in milliseconds
   */
  constructor(duration) {
    this.duration = duration;
    this.startTime = 0;
  }

  /**
   * Check if the cooldown has expired
   * @returns {boolean} - True if the cooldown has expired, false otherwise
   */
  isReady() {
    if (this.startTime === 0) return true;
    const currentTime = Date.now();
